function Get-EnvCollect {
    param(
        [string]$Filter = '',
        [bool]$IncludeUser = $true
    )
    $vars = Get-ChildItem Env:
    if ($Filter) {
        $vars = $vars | Where-Object { $_.Name -like "*$Filter*" }
    }
    $out = @($vars | ForEach-Object {
        @{ name = $_.Name; value = $_.Value }
    })
    $result = @{
        count = $out.Count
        variables = $out
    }
    if ($IncludeUser) {
        $result['username'] = $env:USERNAME
        $result['computer'] = $env:COMPUTERNAME
        $result['domain'] = $env:USERDOMAIN
    }
    return $result | ConvertTo-Json -Depth 3
}

Get-EnvCollect -Filter '{{filter}}' -IncludeUser $([bool]::Parse('{{include_user}}'))
